package com.court.assistant.sms

import android.content.Context
import android.net.Uri
import android.provider.Telephony

data class RawSms(
    val sender: String,
    val body: String,
    val date: Long
)

class SmsReader(private val context: Context) {
    private val courtKeywords = listOf("法院", "开庭", "传票", "案件", "送达", "court.gov.cn", "案号")

    fun readCourtSms(): List<RawSms> {
        val smsList = mutableListOf<RawSms>()
        val uri = Telephony.Sms.CONTENT_URI
        val projection = arrayOf(
            Telephony.Sms.ADDRESS,
            Telephony.Sms.BODY,
            Telephony.Sms.DATE
        )
        val cursor = context.contentResolver.query(
            uri, projection, null, null,
            "${Telephony.Sms.DATE} DESC"
        ) ?: return emptyList()

        cursor.use {
            val addrIdx = it.getColumnIndexOrThrow(Telephony.Sms.ADDRESS)
            val bodyIdx = it.getColumnIndexOrThrow(Telephony.Sms.BODY)
            val dateIdx = it.getColumnIndexOrThrow(Telephony.Sms.DATE)
            while (it.moveToNext()) {
                val body = it.getString(bodyIdx) ?: continue
                if (courtKeywords.any { kw -> body.contains(kw) }) {
                    smsList.add(RawSms(
                        sender = it.getString(addrIdx) ?: "",
                        body = body,
                        date = it.getLong(dateIdx)
                    ))
                }
            }
        }
        return smsList
    }
}

package com.court.assistant.webview

import android.webkit.WebResourceRequest
import android.webkit.WebView
import android.webkit.WebViewClient

class CourtWebViewClient(
    private val onPdfDetected: (url: String) -> Unit,
    private val onPageLoaded: () -> Unit
) : WebViewClient() {

    override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
        val url = request?.url?.toString() ?: return false
        if (isPdfUrl(url)) {
            onPdfDetected(url)
            return true
        }
        return false
    }

    override fun onPageFinished(view: WebView?, url: String?) {
        super.onPageFinished(view, url)
        onPageLoaded()
    }

    private fun isPdfUrl(url: String): Boolean {
        val lower = url.lowercase()
        return lower.endsWith(".pdf") || lower.contains(".pdf?") || lower.contains("getpdf")
    }
}

package com.court.assistant.calendar

import android.content.ContentUris
import android.content.ContentValues
import android.content.Context
import android.provider.CalendarContract
import java.util.*

class CalendarSync(private val context: Context) {

    fun syncHearing(
        caseNumber: String,
        courtName: String?,
        hearingTime: Long,
        defendant: String?,        // 被传唤人
        handler: String?,          // 承办人
        location: String?,         // 应到处所
        phone: String?,            // 电话
        partyNames: String? = null,
        description: String? = null
    ): Long? {
        // 去重：检查是否已存在
        if (eventExists(caseNumber, hearingTime)) return null

        val calendarId = getOrCreateCalendarId() ?: return null
        val title = buildString {
            append("开庭 ")
            if (courtName != null) append("$courtName ")
            append(caseNumber)
        }
        val desc = buildString {
            // 格式化显示精确的开庭时间
            val timeFormat = java.text.SimpleDateFormat("yyyy年MM月dd日 HH:mm", java.util.Locale.CHINA)
            append("⏰ 开庭时间: ${timeFormat.format(java.util.Date(hearingTime))}\n")

            // 7个关键信息字段
            append("案号: $caseNumber")
            if (courtName != null) append("\n法院: $courtName")
            if (defendant != null) append("\n被传唤人: $defendant")
            if (handler != null) append("\n承办人: $handler")
            if (location != null) append("\n应到处所: $location")
            if (phone != null) append("\n电话: $phone")
            if (partyNames != null) append("\n当事人: $partyNames")
            if (description != null) append("\n$description")
        }

        val values = ContentValues().apply {
            put(CalendarContract.Events.CALENDAR_ID, calendarId)
            put(CalendarContract.Events.TITLE, title)
            put(CalendarContract.Events.DESCRIPTION, desc)
            put(CalendarContract.Events.DTSTART, hearingTime)
            put(CalendarContract.Events.DTEND, hearingTime + 2 * 3600 * 1000) // 2小时
            put(CalendarContract.Events.EVENT_TIMEZONE, TimeZone.getDefault().id)
            put(CalendarContract.Events.HAS_ALARM, 1)
        }

        val uri = context.contentResolver.insert(CalendarContract.Events.CONTENT_URI, values)
        val eventId = uri?.let { ContentUris.parseId(it) }

        // 添加提醒：提前1天和1小时
        if (eventId != null) {
            addReminder(eventId, 24 * 60) // 1天
            addReminder(eventId, 60)       // 1小时
        }
        return eventId
    }

    private fun eventExists(caseNumber: String, hearingTime: Long): Boolean {
        val projection = arrayOf(CalendarContract.Events._ID)
        val selection = "${CalendarContract.Events.TITLE} LIKE ? AND ${CalendarContract.Events.DTSTART} = ?"
        val args = arrayOf("%$caseNumber%", hearingTime.toString())
        val cursor = context.contentResolver.query(
            CalendarContract.Events.CONTENT_URI, projection, selection, args, null
        )
        val exists = cursor?.use { it.count > 0 } ?: false
        return exists
    }

    private fun getOrCreateCalendarId(): Long? {
        // 先查找已有日历
        val projection = arrayOf(CalendarContract.Calendars._ID)
        val cursor = context.contentResolver.query(
            CalendarContract.Calendars.CONTENT_URI, projection, null, null, null
        )
        cursor?.use {
            if (it.moveToFirst()) return it.getLong(0)
        }
        return null // 使用系统默认日历
    }

    private fun addReminder(eventId: Long, minutes: Int) {
        val values = ContentValues().apply {
            put(CalendarContract.Reminders.EVENT_ID, eventId)
            put(CalendarContract.Reminders.MINUTES, minutes)
            put(CalendarContract.Reminders.METHOD, CalendarContract.Reminders.METHOD_ALERT)
        }
        context.contentResolver.insert(CalendarContract.Reminders.CONTENT_URI, values)
    }
}

